definition.expression:
def gatherConfigInfos(groupid,articles) {
    my infos = '';
    my weight = '';
    my rohrdicke = 23;
    my bodenabstand = 0;
    my bodenabzug = 0;
    my imperialfactor = 25.4;
    my bodenelement = Localize('[CO][MB] ohne Nivellierfüsse') ++ '@n';
    my group_parts = call groupIdPartList(groupid);
    my notcalculated = Bool(Size(FilterList(group_parts,'element',`Bool(Feature(element, 'calculated'));`)));
    my verticalMetalPanels = FilterList(group_parts,'element',`not IsSubTypeOf(element,'metallverkleidung');`);
    verticalMetalPanels = FilterList(verticalMetalPanels,'element',`not call vertikalVerkleidung(element);`);
    my group_volumes = call groupIdVolumeList(groupid);
    my group_articles_raw = FilterList(articles,'element',`element['groupid'] ne groupid or element['type'] eq 'ar_qs_article';`);
    my group_articles = CompressTable(group_articles_raw, 'key', 'quantity');
   	my cartridge = group_articles[0]['cartridge'];

   	def my tischKlappenInfos(tb){
   		my tischklappe_features = List('f_tischklappenvariante_R','f_tischklappenvariante_M','f_tischklappenvariante_L','f_tischklappenvariante_L_top','f_tischklappenvariante_R_top','f_tischklappenvariante_RL_top','f_tischklappenvariante_RM_top','f_tischklappenvariante_RR_top');
		my klappen_anzahl = 0;
		my klappen_text = '';
		for (my featurename: tischklappe_features) {
			klappen_anzahl = klappen_anzahl + (Feature(tb, featurename) ne 'keine_Klappe' and Feature(tb, featurename) ne '' ? 1 : 0);
		}
		if (klappen_anzahl gt 0) {
			if (klappen_anzahl gt 1){
				klappen_text = klappen_anzahl ++ ' ' ++Localize('Klappen');
			}else {
				klappen_text = klappen_anzahl ++ ' '++ Localize('Klappe');
			}
		}
   	};

   	if (cartridge eq 'usm_haller') {
	    my doortypes = List();
	    my dim = call groupIdDimemsions(group_parts,'measure');
	    my aztuere = '';
	    my azschubtuere = '';
	    my klapptuere = '';
	    my einschubtuere = '';
	    my glastuere = '';
	    my openshelfcount = '';
	    my schublade = '';
	    my tablare = '';
	    my waende = '';
	    my farbe = '';
	    /* Bodenelement */
	    my anz_fussgross = group_articles['key','15167']['quantity'];
	    my anz_fussklein = group_articles['key','15168']['quantity'];
	    if (anz_fussgross or anz_fussklein) {
	       bodenabstand = 40;
	       bodenabzug = 40;
	       bodenelement = Localize('[CO][MB] inkl. Nivellierfüsse') ++ '@n'; 
	    }  

	    my anz_rollegross = group_articles['key','18880']['quantity'];
	    my anz_rollegross_bremse= group_articles['key','18881']['quantity'];
	    if (anz_rollegross or anz_rollegross_bremse) {
	       bodenabstand = 100;
	       bodenabzug = 109;
	       bodenelement = Localize('[CO][MB] inkl. Doppel-Lenkrolle') ++ '@n';  
	    }    

	    my anz_rolle = group_articles['key','10762']['quantity'];
	    my anz_rolle_bremse = group_articles['key','12067']['quantity'];
	    if (anz_rolle or anz_rolle_bremse) {
	       bodenabstand = 80;
	       bodenabzug = 89;
	       bodenelement = Localize('[CO][MB] inkl. Lenkrolle weich') ++ '@n'; 
	    } 

	    my anz_rollehart = group_articles['key','10761']['quantity'];
	    my anz_rollehart_bremse = group_articles['key','12066']['quantity'];
	    if (anz_rollehart or anz_rollehart_bremse) {
	       bodenabstand = 80;
	       bodenabzug = 89;
	       bodenelement = Localize('[CO][MB] inkl. Lenkrolle hart') ++ '@n'; 
	    }
	    /* Imperial */
	    if (UnitSystem() eq 'imperial') {
	    	bodenabstand = Round(bodenabstand / imperialfactor, 0.01);     
	    	bodenabzug = Round(bodenabzug / imperialfactor, 0.01); 
	    	rohrdicke = Round(rohrdicke / imperialfactor, 0.01);    
	    } 
	    /* Groesse */
	    my dimensions = Localize('[CO][MB] LxTxH:') ++ ' ' ++ (dim[2] + rohrdicke) ++ 'x' ++ (dim[1] + rohrdicke) ++ 'x' ++ (dim[0] - bodenabzug + bodenabstand) ++ ' ' ++ dim[4];
	    dimensions = notcalculated ? dimensions ++ '   ' ++ Localize('[CO][MB] inkl. nicht kalkulierter Teile') ++ '@n' : dimensions ++ '@n';
	    /* Material  + Farben 
	       Do not inclued soft panels */
	    my materials = call configColor(FilterList(group_articles, 'element', `element['type'] eq 'ar_soft_panel';`));
	    my material = Localize('[CO][MB] Material') ++ ': ' ++ materials[0] ++ '@n';
	    farbe = Localize('[CO][MB] Farbe') ++ ': ' ++ materials[1] ++ '@n';
	    /* Gewicht */
	    for (my art : CopyTable(group_articles)) {
	     	weight = weight + Number(art['weight']) * Number(art['quantity']);
	    }
	    weight = Localize('[CO][MB] Gewicht:') ++ ' ' ++ Round(weight,0.001) ++ Localize('[CO][MB] kg') ++ '@n';

	    /* Tueren */
	    doortypes = call doorTypes(group_volumes);
	    aztuere = doortypes[0];   
	    azschubtuere = doortypes[1];   
	    klapptuere = doortypes[2];
	    einschubtuere = doortypes[3];   
	    glastuere = doortypes[4];       
	    schublade = doortypes[5];  
	    openshelfcount = doortypes[6];


	    /* Soft Panels */
	    my soft_panels = FilterList(group_articles, 'element', `element['type'] ne 'ar_soft_panel';`);
		for(my i =0; i lt Size(soft_panels); i = i + 1){
			my name_list = StringToList(soft_panels[i]['name'], ',');
			/* get last two elements */
			my desc_list = ListSplice(name_list, Size(name_list)-2, -1, 0);
			soft_panels[i]['short_description'] = Trim(ListToString(desc_list, ','));
		}
		soft_panels = CompressTable(soft_panels, List('short_description'), List('quantity'));

		my soft_panel_desc = '';

		for(my panel : soft_panels){
			soft_panel_desc = soft_panel_desc ++ String(panel['quantity'])++ 'x ' ++ Localize('SoftPanel') ++ ', ' ++ panel['short_description'] ++ '@n';
		}


	    /* Tablare */ 
	    tablare = call tablarTypes(group_volumes);
	    my tablarinfo = tablare['shelfinfo'];
	    openshelfcount = openshelfcount - tablare['shelfcount'];

	    my othercontent = call contentTypes(group_volumes);
	    my contentinfo = othercontent['shelfinfo'];

	    waende = call panelingTypes(group_volumes)++'@n';
	    my openshelf = Bool(openshelfcount) ? openshelfcount ++ 'x ' ++ Localize('[CO][MB] offenes Fach') ++ '@n' : '';

	    my regalverbindercount = Size(FilterList(ChildrenListOfTypeDeepA(Forest('articlestructure'), 'RegalVerbinder'), 'a', `not (Feature(AnyLeaf(a), '_PXi_permanent_group_id') eq groupid);`));
	    my regalverbinder = regalverbindercount ? regalverbindercount ++ 'x ' ++ Localize('[CO][MB] Regalverbinder') ++ '@n' : '';

	    my wandverankerungcount = Size(FilterList(ChildrenListOfTypeDeepA(Forest('articlestructure'), 'Wandverankerung'), 'a', `not (Feature(AnyLeaf(a), '_PXi_permanent_group_id') eq groupid);`));
	    my wandverankerung =  wandverankerungcount ? wandverankerungcount ++ 'x ' ++ Localize('[CO][MB] Wandverankerung') ++ '@n' : '';

	    my bodenverankerungcount = Size(FilterList(ChildrenListOfTypeDeepA(Forest('articlestructure'), 'Bodenverankerung'), 'a', `not (Feature(AnyLeaf(a), '_PXi_permanent_group_id') eq groupid);`));
	    my bodenverankerung = bodenverankerungcount ? bodenverankerungcount ++ 'x ' ++ Localize('[CO][MB] Bodenverankerung') ++ '@n' : '';

	    my ggwcount = Size(FilterList(ChildrenListOfTypeDeepA(Forest('articlestructure'), 'Gewichtsplatte_Set'), 'a', `not (Feature(AnyLeaf(a), '_PXi_permanent_group_id') eq groupid);`));
	    my ggw =  ggwcount ? ggwcount ++ 'x ' ++ Localize('[CO][MB] Gegengewichtsplatten') ++ '@n' : '';


	    my blechausschnittcount = Size(FilterList(ChildrenListOfTypeDeepA(Forest('articlestructure'), 'Blechausschnitt'), 'a', `not (Feature(AnyLeaf(a), '_PXi_permanent_group_id') eq groupid);`));
	    my blechausschnitt =  blechausschnittcount ? blechausschnittcount ++ 'x ' ++ Localize('[CO][MB] Blechausschnitt') ++ '@n' : '';

		/*if (Scenario() eq 'web') {
		    my inoscount = Size((my boxen = ChildrenListOfTypeDeep(Forest('mainstructure'), 'at_inosBox')));
		    my kastensetcount = Size(ChildrenListOfTypeDeep(Forest('mainstructure'), 'kastenset'));
		    my topfcount = Size((my topflist = ChildrenListOfTypeDeep(Forest('mainstructure'), 'co_pflanzentopf')));
		    my inoscolorlist = UniqueList(FeatureValuesFromPartList(boxen, 'f_inosBoxMaterial'));
		    my inosfarbe = inoscount gt 0 ? call getRALFromColorcodes(inoscolorlist, ', ', false, false) : '';
		    my inos = inoscount gt 0 ? Format(Localize('%0x [CO][MB] Inos Box, %1'), inoscount, inosfarbe)++'@n' : '';
		    my kastensetfarbe = kastensetcount gt 0 ? call getRALFromColorcodes(call globalColorList(GetComponentListOfType('schalenkasten'), false, true), ', ', false, false) : '';
		    my kastenset = kastensetcount gt 0 ? Format(Localize('%0x [CO][MB] Schubladenkasten')++', %1', kastensetcount, kastensetfarbe)++'@n' : '';
		    my pflanzentopffarbe = topfcount gt 0 ? Localize(Feature(topflist[0], 'f_topffarbe')) : '';
		    my pflanzentopf = topfcount gt 0 ? Format(Localize('%0x [CO][MB] Pflanzentopf, %1'), topfcount, pflanzentopffarbe)++'@n' : '';

		    infos = '@n';
		    infos = infos ++dimensions++ weight ++ material ++ farbe ++ bodenelement;
		    infos = infos ++'@n';
		    infos = infos ++ klapptuere ++ aztuere ++ azschubtuere ++ einschubtuere ++ glastuere ++ schublade ++ tablarinfo;
		    if ((inoscount + kastensetcount + topfcount) gt 0) {
			    infos = infos ++'@n';
			    infos = infos ++ inos  ++ kastenset ++ pflanzentopf;
			};
	    } else {*/
	    	infos = 
	    		dimensions ++ 
	    		weight ++
	    		material ++ 
	    		farbe ++ 
	    		/*summarizedVolumeInfo ++ 		-->Informationen werden nicht mehr auf die einzelnen Fächer aufsummiert.
	    		openshelf  ++ */

	    		klapptuere ++ 
	    		aztuere ++ 
	    		azschubtuere ++ 
	    		einschubtuere ++ 
	    		glastuere ++
	    		soft_panel_desc ++ 
	    		schublade ++ 
	    		tablarinfo ++

	    		regalverbinder++
	    		wandverankerung++
	    		bodenverankerung++
	    		ggw++
	    		blechausschnitt++


	    		/** Ausstattung */
	    		contentinfo++

	    		bodenelement;
	   /* };*/
	};

	if (cartridge eq 'usm_hallertisch') {

		my tischblatt_list = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'tischblatt'));`);
		my tischblatt_advanced = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'ct_kabelwanne_i'));`);
		my tischblatt_i_list = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'ct_tisch_i'));`);
		my bein_list = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'tischbein'));`);
		my bein_vario_list = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'tischbein_vario'));`);
		my laenge = 'undef';
		my breite = 'undef';
		my hoehe = 'undef';
		my material = 'undef';
		my hoehenverstellbar = '';
		my klappen_text ='';
		if (Size(tischblatt_list) and Scenario() ne 'web'){
			infos = Localize('usm_hallertisch');
		}
		if (Size(tischblatt_i_list)){
			infos = Localize('[CO]: Hallertisch integral standard');
		}
		if (Size(tischblatt_advanced)){
			infos = Localize('[CO]: Hallertisch integral advanced');
		};

		if (Size(tischblatt_list)) {
			my tb = tischblatt_list[0];
			laenge = PartAttr(tb, 'laenge')*10;
			breite = PartAttr(tb, 'breite')*10;
			material = Feature(tb, 'Tischmaterial');
		}
		if (Size(bein_list)) {
			hoehe = SubStr(GetTypeName(bein_list[0]), IndexOfSubStr(GetTypeName(bein_list[0]), '_') +1)*10;
		}

		if (Size(bein_vario_list)) {
			hoehe = '680-860';
			hoehenverstellbar = Localize('pty_Vario_Tisch');
		}

		if (Size(tischblatt_list)) {
			my dimensions = Localize('[CO][MB] LxTxH:') ++ ' ' ++laenge++'x'++breite++'x'++hoehe++' mm';
			infos = infos ++ '@n'++dimensions;
		};

		if (StrLen(hoehenverstellbar)) {
			infos = infos ++ '@n'++hoehenverstellbar;
		};

		klappen_text = call tischKlappenInfos(tb);
		if(klappen_text ne 0){
			infos = infos ++ '@n'++klappen_text;
		};

		if (Size(tischblatt_list)) {
			my tischblatt = tischblatt_list[0];
			my tischmaterial = tischblatt ? Feature(tischblatt, 'Tischmaterial') : ''; 
			if (tischmaterial ne '') {
				my hint_text = Localize('key_hint_'++FillLeft(tischmaterial,2,'0'));	
				infos = infos ++'@n'++Format(Localize('Material')++': %0', hint_text); 
			};
		};
	};

	if (cartridge eq 'usm_kitos') {

		my tischblatt_list = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'ct_tischblatt'));`);
		my tischblatt_kitos = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'tischblatt'));`);
		my tischblatt_plus = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'ct_fuehrungswinkel_plus'));`);
		my tischblatt_meeting = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'ct_tischblatt_meeting'));`);
		my tischblatt_freistehend_rechteckig = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'ct_tischblatt_frst_eckig'));`);
		my tischblatt_freistehend_rund = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'ct_tischblatt_frst_rund'));`);
		my kabelwanne = FilterList(group_parts, 'p', `not (IsSubTypeOf(p, 'ct_kabelwanne'));`);
		my klappen_text = '';
		my kabel= kabelwanne[0];
		my tb = tischblatt_list[0];
		my tbk = tischblatt_kitos[0];
		my tisch_e = (ParentOfType(tb, 'mainstructure', 'at_tisch_e'));
		my tisch_m = (ParentOfType(tb, 'mainstructure', 'at_tisch_m'));
		my tisch_k = (IsSubTypeOf(tbk, 'standardtischblatt_1s'));

		if (Size(tischblatt_list) and IsSubTypeOf(tisch_m, 'at_tisch_m')){
			infos = Localize('Kitos M');
		};
		if (Size(tischblatt_list) and IsSubTypeOf(tisch_e, 'at_tisch_e')){
			infos = Localize('USM Kitos E');
		};
		if (Size(tischblatt_plus) and IsSubTypeOf(tisch_m, 'at_tisch_m')){
			infos = Localize('Kitos M Plus');
		};
		if (Size(tischblatt_plus) and IsSubTypeOf(tisch_e, 'at_tisch_e')){
			infos = Localize('USM Kitos E Plus');
		};
		if (Size(tischblatt_meeting) and IsSubTypeOf(tisch_m, 'at_tisch_m')){
			infos = Localize('Kitos M Meeting'); 
		};
		if (Size(tischblatt_meeting) and IsSubTypeOf(tisch_e, 'at_tisch_e')){
			infos = Localize('Kitos E Meeting'); 
		};
		if (Size(tischblatt_freistehend_rechteckig)){
			infos = Localize('USM Kitos E freistehend quadratisch');
		};
		if (Size(tischblatt_freistehend_rund)){
			infos = Localize('USM Kitos E freistehend rund');
		};
		if (Size(tischblatt_kitos) and tisch_k eq true){
			infos = Localize('USM Kitos freistehend quadratisch');
		};
		if (IsSubTypeOf(tbk, 'tischblatt_standard') and (Size(tischblatt_kitos))){
			infos = Localize('USM Kitos');
		};

		if (IsSubTypeOf(tb, 'ct_tischblatt')) {

			my dimension = call getKitosDimension(tb, false);
			my basic_e_text = '';
			my tisch_e = (ParentOfType(tb, 'mainstructure', 'at_tisch_e_einheit'));
			my vario = (ParentOfType(tb, 'mainstructure', 'as_tisch_tio_vario'));
			my vario_text = '';
			my klappe = call tischKlappenInfos(tb);

			if (vario and IsSubTypeOf(vario, 'as_tisch_tio_vario')){
				my basic_e_text = 'x700-1110';
				vario_text = Localize('pty_Vario_Tisch');
				}
				else{
					my basic_e_text = 'x740';
			};
			if (kabel ne null){
				my f = Feature(kabel, 'f_saeulenpaar');
				if (Size(tisch_e) and f eq 'saeulenpaar_e3'){
					my basic_e_text = 'x650-1300';
					vario_text = Localize('pty_Vario_Tisch');
				}
				if (Size(tisch_e) and f eq 'saeulenpaar_e2'){
					my basic_e_text = 'x700-1200';
					vario_text = Localize('pty_Vario_Tisch');
				}
				if (Size(tisch_e) and f eq 'saeulenpaar_e1'){
					my basic_e_text = 'x740';
				}
			};
			if (tisch_m and Size(tischblatt_meeting)){
				my basic_e_text = 'x700-1150';
				vario_text = Localize('pty_Vario_Tisch');
			};
			if (tisch_m and not Size(tischblatt_meeting) and IsSubTypeOf(tisch_m, 'at_tisch_m')){
				my basic_e_text = 'x700-1200';
				vario_text = Localize('pty_Vario_Tisch');
			};
			my dimension_text = Localize('[CO][MB] LxTxH:') ++ ' ' ++ dimension  ++ basic_e_text ++ ' mm';

			infos = infos ++ '@n'++dimension_text;

			if (klappe ne 0){
				klappen_text = klappe;
				infos = infos ++ '@n'++klappen_text;
			};
		};

		if ((Size(tischblatt_kitos) and IsSubTypeOf(tbk, 'tischblatt_standard')  )) {
			my dimension_k = call getKitosDimension(tbk, false);
			my basic_e_text = '';
			my vario_text = '';
			my vario = (ParentOfType(tbk, 'mainstructure', 'tisch_normal'));
			my zweisaeulen = (ParentOfType(tbk, 'mainstructure', 'zweisaeuliger_tisch'));

			if (vario){
				my key = Property(vario, 'hc_saeulen'); 
				basic_e_text = if(key eq 'saeule_A740') {'x740';} 
									else if(vario and vario eq zweisaeulen) {'x700-1200';}
									else if (key eq 'saeule_B1') {'x681-1081';}
									else if (key eq 'saeule_B2') {'x680-1090';};
				if (key eq 'saeule_B1' or key eq 'saeule_B2'){
					vario_text = Localize('pty_Vario_Tisch');
				};
			}; 
			my dimension_text = Localize('[CO][MB] LxTxH:') ++ ' ' ++ dimension_k ++ basic_e_text ++ ' mm';

			infos = infos ++ '@n'++dimension_text;
		};
		if (tb or tbk) {
			my tischblatt = tb ? tb : tbk;
			my tischmaterial = tischblatt ? Feature(tischblatt, 'Tischmaterial') : ''; 
			if (tischmaterial ne '') {
				my hint_text = Localize('key_hint_'++FillLeft(tischmaterial,2,'0'));	
				infos = infos ++'@n'++Format(Localize('Material')++': %0', hint_text); 
			};
		};
		if(StrLen(vario_text)){
			infos = infos ++ '@n' ++ vario_text;
		};

	};

	return  infos;
  };

def getKitosDimension(tischblatt, with_unit) {
		my dimension = '';
        my length = Round(PartAttr(tischblatt,'length')) * 10;
        my length_2 = Round(PartAttr(tischblatt,'length_2')) * 10;
        my width = Round(PartAttr(tischblatt,'width')) * 10;
        my radius = PartAttr(tischblatt,'radius') * 10;
        if (length_2 eq 0) {
         dimension = length ++ 'x' ++ width;
        } else {           dimension = length ++ 'x' ++ width ++ 'x' ++ length_2;
        }
        if (PartAttr(tischblatt,'radius') gt 0) {
           dimension = 2*radius;
        }

        if (with_unit) {
			dimension = dimension ++ ' mm';        
        }
        return dimension;
	}

def configColor(group_articles) {
    my materials = List();
    my material = '';
    my glasmaterial = '';
    my metalmaterial = '';
    my colors = '';
    my colorlist = List();
    my colorTable = List();
    for (my i : IndexList(Size(group_articles))) {
        colorTable[i]['quantity'] = group_articles[i]['quantity']; 
        my col = '';

        my key = group_articles[i]['key'];
        /* my inos = EndsWith(BASE['key',key]['Kurzbezeichnung'],'Bibliotheks-Rasterschiene') or EndsWith(BASE['key',key]['Zubhoer'],'inos'); */

        my splitcol = StringToList(key,'.'); 
        if (InList(ALLGLASSES,splitcol[0])) {
           col = 80;
           glasmaterial = Localize('[CO][MB] Glas');
        } else if (StrLen(splitcol[1]) gt 1) {
            if (BeginsWith(group_articles[i]['name'],'USM Haller')) {
              col = splitcol[1];
              if (StrLen(col) eq 2 or StrLen(col) eq 4) {
                /* nur Metallfarben, keine Schloesser und keine PPs Farben */
                 metalmaterial = Localize('[CO][MB] Metall');
              } else {
                col = '';
              }
            }
        } else {
          col = '';
        }
        colorTable[i]['colorcode'] = col;  
      }
      colorTable = FilterList(colorTable,'element',`element['colorcode'] eq '';`);
      colorlist = CompressTable(colorTable, 'colorcode', 'quantity');
      material = StrLen(metalmaterial) gt 0 ? material = metalmaterial : material;
      material = StrLen(glasmaterial) gt 0 ? material = glasmaterial : material;
      material = StrLen(metalmaterial) gt 0 and StrLen(glasmaterial) gt 0 ? material = metalmaterial ++ ', ' ++ glasmaterial : material;
      for (my j : IndexList(Size(colorlist))) {
        my color = colorlist[j]['colorcode'];
        if (StrLen(color) eq 2 or StrLen(color) eq 4) {
            color = colornames['Farbcode',color]['Bezeichnung_'++UpperCase(EnvValue('DYNAMIC.Language'))];   
            color = StrLen(color) ? color : '['++colorlist[j]['colorcode']++']';      
          if (StrLen(colors) eq 0) {
          colors = color;
          } else {
           colors = colors ++ ', ' ++ color;
          }
        }
      }
      materials[0] = material;
      materials[1] = colors;
      return materials;
    }

