def getAllInosBoxenOfVolume(volume) {
		my boxen = List();
		my top_panel_list = FilterList(GetVolumeRefParts(volume), 'p', `not (IsSubTypeOf(p, 'verkleidung') and FindPart(p, 'ct_inosBox'));`);
		for (my p: top_panel_list) {
		 	my blist = call connectedPartsByDockType(p, 'dt_tablar_2_inosBox');
		 	for (my b: blist) { 
		 		my box = call getRootParentOfType(b, 'mainstructure', 'at_inosBoxKonzept');
		 		if (box) {
		 			if (IsSubTypeOf(box, 'as_inosBoxStappel')) { 
		 				ListExtend(boxen, ChildrenListOfTypeDeep(box, 'as_inosBox'));

		 			} else {
		 				ListAdd(boxen, box);
		 			}
		 		};
		 	};
		};

		my tablar_list = FilterList(ChildrenListOfTypeDeep(volume, 'ct_tablar'), 'p', `not (FindPart(p, 'ct_inosBox'));`);
		for (my p: tablar_list) {
		 	my blist = call connectedPartsByDockType(p, 'dt_tablar_2_inosBox');
		 	for (my b: blist) {
		 		my box = call getRootParentOfType(b, 'mainstructure', 'at_inosBoxKonzept');
		 		if (box) {
		 			if (IsSubTypeOf(box, 'as_inosBoxStappel')) { 
		 				ListExtend(boxen, ChildrenListOfTypeDeep(box, 'as_inosBox'));

		 			} else {
		 				ListAdd(boxen, box);
		 			}
		 		};
		 	};
		};

		return boxen;
	}

def contentTypes(group_volumes) {
    my result = List();
	result['shelfcount'] = 0;
    my anz_inos = 0;
    my anz_kastenset = 0;
    my anz_pflanzen = 0;
    my inoslist = List();
    my kastensetlist = List();
    my pflanzenlist = List();

    my shelflist = List();
    my headers = List('count','inos','kastenset','pflanzen');
    my values = List('','','','');
    my contenttable = CreateTable(headers,values);
    my contentlist = List();
    my contenttext = '';

    for (my i : IndexList(Size(group_volumes))) {
		my v = group_volumes[i];
		/** inos boxen in oder an volume oder auf tablar in volume */
		my iblist = call getAllInosBoxenOfVolume(v);
		for (my b: iblist) {
			not InList(inoslist, b) ? ListAdd(inoslist, b) : null;
		}
		my klist = ChildrenListOfTypeDeep(v, 'schalenkasten');
		for (my b: klist) {
			not InList(kastensetlist, b) ? ListAdd(kastensetlist, b) : null;
		}
		my topflist = FilterList(call getAllPflanzenOfVolume(v), 'p', `not (IsSubTypeOf(p, 'co_pflanzentopf'));`);
		for (my t: topflist) {
			not InList(pflanzenlist, t) ? ListAdd(pflanzenlist, t) : null;
		}
    } 

    anz_inos = Size(inoslist);
    anz_kastenset = Size(kastensetlist);
    anz_pflanzen = Size(pflanzenlist);

    my inoscolorlist = anz_inos ? UniqueList(FeatureValuesFromPartList(inoslist, 'f_inosBoxMaterial_top')) : List();
    my inosfarbe = anz_inos gt 0 ? call getRALFromColorcodes(inoscolorlist, ', ', false, false) : '';
    my inos = anz_inos gt 0 ? Format(Localize('%0x [CO][MB] Inos Box, %1'), anz_inos, inosfarbe)++'@n' : '';
    my kastensetfarbe = anz_kastenset gt 0 ? call getRALFromColorcodes(call globalColorList(kastensetlist, false, true), ', ', false, false) : ''; 
    my kastenset = anz_kastenset gt 0 ? Format(Localize('%0x [CO][MB] Schubladenkasten'), anz_kastenset)++ ', ' ++ kastensetfarbe ++'@n' : '';
    my pflanzentopffarbe = anz_pflanzen gt 0 ? Localize(Feature(pflanzenlist[0], 'f_topffarbe')) : '';
    my pflanzentopf = anz_pflanzen gt 0 ? Format(Localize('%0x [CO][MB] Pflanzentopf'), anz_pflanzen)++ ', ' ++ pflanzentopffarbe ++ '@n' : '';

    if ((anz_inos + anz_kastenset + anz_pflanzen) gt 0) {
	    result['shelfinfo'] = result['shelfinfo'] + 1;
	    contenttext = contenttext ++ inos  ++ kastenset ++ pflanzentopf;
	};

    result['shelfinfo'] = contenttext;


   return result;
   }

def doorTypes(group_volumes) {
   my doors = List();
   my aztueren = List();
   my aztuerenschublade = List();
   my klapptueren = List();
   my einschubtueren = List();
   my glastueren = List();
   my schubladen = List();
   my calc_open_shelf = call calcopenshelf(group_volumes);
   my calc_group_volumes = call groupIdCalcVolumeList(calc_open_shelf);
   for (my vol : group_volumes) {
     my aztuereschublade = call countDoor(vol,'aztuerschubladenset','tuerelement');
     if (aztuereschublade) {
      aztuerenschublade = ListAdd(aztuerenschublade, aztuereschublade);
     }else {
	     my aztuere = call countDoor(vol,'aztuertabset_norm','tuerelement');
	     if (aztuere) {
	      aztueren = ListAdd(aztueren, aztuere);
	     }
	     my aztuere = call countDoor(vol,'aztuertabset_kurz','tuerelement');
	     if (aztuere) {
	      aztueren = ListAdd(aztueren, aztuere);
	     }
     }
     my klapptuere = call countDoor(vol,'klapptuerset','tuerelement');
     if (klapptuere) {
       klapptueren = ListAdd(klapptueren, klapptuere);
     }
     my einschubtuere = call countDoor(vol,'einschubtuerset','einschubtuer');
     if (einschubtuere) {
      einschubtueren = ListAdd(einschubtueren, einschubtuere);
     }
     my glastuere = call countDoor(vol,'glastuerset','glastuer');
     if (glastuere) {
      glastueren = ListAdd(glastueren, glastuere);
     }
     my schublade = call countDoor(vol,'schubladenauszugset','schublade');
     if (schublade) {
      schubladen = ListAdd(schubladen, schublade);
     }
   }
   /* Message(Size(group_volumes) ++ ', ' ++ Size(aztueren) ++ ', ' ++ Size(klapptueren) ++ ', ' ++ Size(einschubtueren) ++ ', ' ++  Size(glastueren)); */
   my countfachoffen = Size(calc_group_volumes) - (Size(aztueren) + Size(klapptueren) + Size(einschubtueren) + Size(glastueren) + Size(schubladen));
   my nrofdoors = List();
   my keys = List('name','amount');
   ListAdd(nrofdoors,Dictionary(keys,List('Ausziehtüre',Size(aztueren))));
   ListAdd(nrofdoors,Dictionary(keys,List('Ausziehtüre Schublade',Size(aztuerenschublade))));
   ListAdd(nrofdoors,Dictionary(keys,List('Klapptüre',Size(klapptueren))));
   ListAdd(nrofdoors,Dictionary(keys,List('Einschubtüre',Size(einschubtueren))));
   ListAdd(nrofdoors,Dictionary(keys,List('Glastüre',Size(glastueren))));
   ListAdd(nrofdoors,Dictionary(keys,List('Schubladen',Size(schubladen))));
   my aztinfo = Bool(Size(aztueren)) ? call doorInfo(aztueren,'azt') : '';
   my aztschubinfo = Bool(Size(aztuerenschublade)) ? call doorInfo(aztuerenschublade,'aztschub') : '';
   my klappinfo = Bool(Size(klapptueren)) ? call doorInfo(klapptueren,'klapp') : '';
   my einschubinfo = Bool(Size(einschubtueren)) ? call doorInfo(einschubtueren,'schub') : '';
   my glastuerinfo = Bool(Size(glastueren)) ? call doorInfo(glastueren,'glas') : '';
   my schubladeinfo = Bool(Size(schubladen)) ? call doorInfo(schubladen,'lade') : '';
   doors[0] = aztinfo;
   doors[1] = aztschubinfo;
   doors[2] = klappinfo;     
   doors[3] = einschubinfo;  
   doors[4] = glastuerinfo;  
   doors[5] = schubladeinfo; 
   doors[6] = countfachoffen;
   doors[7] = nrofdoors; 
   return doors;
   }

def groupIdCalcVolumeList(group_volumes) {
			my calc_volumes = List();
			for ( my vol : group_volumes ) { 
				my rohre = FilterList(GetVolumeRefParts(vol),'element',`not IsSubTypeOf(element,'rohr');`);
				rohre = FilterList(rohre,'element',`not Bool(Feature(element,'calculated'));`);
				if ( Bool(Size(rohre)) ) {
					calc_volumes = ListAdd(calc_volumes,vol);
				}
			}
			return calc_volumes;
	}

def calcopenshelf(group_volumes) {
		my calc_volumes = List();
		my verkleidung = List();
			for ( my vol : group_volumes ) 
			{ 
				verkleidung = FilterList(GetVolumeRefParts(vol),'e',`not IsSubTypeOf(e,'verkleidung');`);

				if (Size(verkleidung) lt 6)
				{
					calc_volumes = ListAdd(calc_volumes,vol);
				}
			}

		return calc_volumes;


	}

def doorInfo(doors, kind) {
    my griffinfo = '';
   /* my tuerinfo = Localize('[CO][MB] Fach inkl.');  */
    my tuerinfo = '';
    if (kind eq 'azt') {
      tuerinfo = tuerinfo ++ Localize('[CO][MB] Ausziehtüre');
    } else if (kind eq 'aztschub') {
      tuerinfo = tuerinfo ++ Localize('[CO][MB] Ausziehtüre mit Einlegerahmen');
    } else if (kind eq 'klapp') {
      tuerinfo = tuerinfo ++ Localize('[CO][MB] Klapptüre');
    } else if (kind eq 'schub') {
      tuerinfo = tuerinfo ++ Localize('[CO][MB] Einschubtüre');
    } else if (kind eq 'glas') {
      tuerinfo = tuerinfo ++ Localize('[CO][MB] Glastüre');
    } else if (kind eq 'lade') {
      tuerinfo = tuerinfo ++ Localize('[CO][MB] Schubladen');
    }
    my anz_griff_normal = Size(FilterList(doors,'element',`not ChildOfTypeDeep(element, 'griff_normal');`));
    if (Bool(anz_griff_normal)) {
       griffinfo = anz_griff_normal ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Griff (ohne Schloss)') ++ '@n';
    }
    my anz_griff_m_nummer = Size(FilterList(doors,'element',`not ChildOfTypeDeep(element, 'griff_m_nummer');`));
    if (Bool(anz_griff_m_nummer)) {
       my schloesser = List();
       my anz_c_schloesser = 0;
       for(my door : FilterList(doors,'element',`not ChildOfTypeDeep(element, 'griff_m_nummer');`)){
       		ListAdd(schloesser, ChildOfTypeDeep(door, 'griff_m_nummer'));
       }
       my schlossNr = '';
       my marked_schloesser = List();
       for(my schloss : schloesser){
       		if(Feature(schloss, 'Schliessung') ~ 'schloss_c'){
       			anz_griff_m_nummer = anz_griff_m_nummer - 1;
       			anz_c_schloesser = anz_c_schloesser + 1;
       		} else {
       			my prefix = StrLen(schlossNr) GT 0 ? ', $' : ' $';
       			my schloss_key = HALLERARTICLE['type',GetTypeName(Parent('articlestructure',schloss))]['value'] ++ (StrLen(Feature(schloss,'lockid')) gt 0? '_'++Feature(schloss,'lockid') : '$');
       			if (not InList(marked_schloesser, schloss_key)){
	       			schlossNr = schlossNr ++ prefix ++ schloss_key;
	       			ListAdd(marked_schloesser, schloss_key);
	       		}
       		}
       }

       if (Bool(anz_griff_m_nummer)) {
       		griffinfo = griffinfo ++ anz_griff_m_nummer ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Griff (mit Schloss)') ++ schlossNr ++ '@n';
       }
       if (Bool(anz_c_schloesser)) {
       		griffinfo = griffinfo ++ anz_c_schloesser ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Griff (mit C-Schloss)') ++ '@n';
       }
    }
    my anz_schnapp_griff_normal = Size(FilterList(doors,'element',`not ChildOfTypeDeep(element, 'schnapp_griff_normal');`));
    if (Bool(anz_schnapp_griff_normal)) {
       griffinfo = griffinfo ++ anz_schnapp_griff_normal ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Schnappdrehgriff (ohne Schloss)') ++ '@n';
    }
    my anz_schnapp_griff_m_nummer = Size(FilterList(doors,'element',`not ChildOfTypeDeep(element, 'schnapp_griff_m_nummer');`));
    if (Bool(anz_schnapp_griff_m_nummer)) {
       my schloesser = List();
       my anz_c_schloesser = 0;
       for(my door : FilterList(doors,'element',`not ChildOfTypeDeep(element, 'schnapp_griff_m_nummer');`)){
       		ListAdd(schloesser, ChildOfTypeDeep(door, 'schnapp_griff_m_nummer'));
       }
       my schlossNr = '';
       my marked_schloesser = List();
       for(my schloss : schloesser){
       		if(Feature(schloss, 'Schliessung') ~ 'schloss_c'){
       			anz_schnapp_griff_m_nummer = anz_schnapp_griff_m_nummer - 1;
       			anz_c_schloesser = anz_c_schloesser + 1;
       		} else {
       			my prefix = StrLen(schlossNr) GT 0 ? ', $' : ' $';
       			my schloss_key = HALLERARTICLE['type',GetTypeName(Parent('articlestructure',schloss))]['value'] ++ (StrLen(Feature(schloss,'lockid')) gt 0? '_'++Feature(schloss,'lockid') : '$');
       			if (not InList(marked_schloesser, schloss_key)){
	       			schlossNr = schlossNr ++ prefix ++ schloss_key;
	       			ListAdd(marked_schloesser, schloss_key);
	       		}
       		}
       }
       if (Bool(anz_schnapp_griff_m_nummer)) {
       		griffinfo = griffinfo ++ anz_schnapp_griff_m_nummer ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Schnappdrehgriff (mit Schloss)') ++ schlossNr ++ '@n';
       }
       if (Bool(anz_c_schloesser)) {
       		griffinfo = griffinfo ++ anz_c_schloesser ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Schnappdrehgriff (mit C-Schloss)') ++ '@n';
       }
    }
    my chromgriff = Size(FilterList(doors,'element',`not ChildOfTypeDeep(element, 'chromgriff');`));
    if (Bool(chromgriff)) {
       griffinfo = griffinfo ++ chromgriff ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Chromgriff (ohne Schloss)') ++ '@n';
    }
    my glasgriff_schloss_m = Size(FilterList(doors,'element',`not ChildOfTypeDeep(element, 'glasgriff_schloss_m');`));
    if (Bool(glasgriff_schloss_m)) {
       my schloesser = List();
       my anz_c_schloesser = 0;
       for(my door : FilterList(doors,'element',`not ChildOfTypeDeep(element, 'glasgriff_schloss_m');`)){
       		ListAdd(schloesser, ChildOfTypeDeep(door, 'glasgriff_schloss_m'));
       }
       my schlossNr = '';
       my marked_schloesser = List();
       for(my schloss : schloesser){
       		if(Feature(schloss, 'Schliessung') ~ 'schloss_c'){
       			glasgriff_schloss_m = glasgriff_schloss_m - 1;
       			anz_c_schloesser = anz_c_schloesser + 1;
       		} else {
       			my prefix = StrLen(schlossNr) GT 0 ? ', $' : ' $';
       			my schloss_key = HALLERARTICLE['type',GetTypeName(Parent('articlestructure',schloss))]['value'] ++ (StrLen(Feature(schloss,'lockid')) gt 0? '_'++Feature(schloss,'lockid') : '$');
       			if (not InList(marked_schloesser, schloss_key)){
	       			schlossNr = schlossNr ++ prefix ++ schloss_key;
	       			ListAdd(marked_schloesser, schloss_key);
	       		}
       		}
