       		griffinfo = griffinfo ++ anz_c_schloesser ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Glasgriff (mit C-Schloss)') ++ '@n';
       }
    }
    my anz_schubladenGriff = Size(FilterList(doors,'element',`ChildOfTypeDeep(element, 'schublade_schloss_num');`));
    if (Bool(anz_schubladenGriff) and kind eq 'lade') {
       griffinfo = griffinfo ++ anz_schubladenGriff ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Schubladengriff (ohne Schloss)') ++ '@n';
    }
    my anz_schubladenSchloss = Size(FilterList(doors,'element',`not ChildOfTypeDeep(element, 'schublade_schloss_num');`));
    if (Bool(anz_schubladenSchloss)) {
       my schloesser = List();
       my anz_c_schloesser = 0;
       for(my door : FilterList(doors,'element',`not ChildOfTypeDeep(element, 'schublade_schloss_num');`)){
       		ListAdd(schloesser, ChildOfTypeDeep(door, 'schublade_schloss_num'));
       }
       my schlossNr = '';
       my marked_schloesser = List();
       for(my schloss : schloesser){
       		if(Feature(schloss, 'Schliessung') ~ 'schloss_c'){
       			anz_schubladenSchloss = anz_schubladenSchloss - 1;
       			anz_c_schloesser = anz_c_schloesser + 1;
       		} else {
       			my prefix = StrLen(schlossNr) GT 0 ? ', $' : ' $';
       			my schloss_key = HALLERARTICLE['type',GetTypeName(Parent('articlestructure',schloss))]['value'] ++ (StrLen(Feature(schloss,'lockid')) gt 0? '_'++Feature(schloss,'lockid') : '$');
       			if (not InList(marked_schloesser, schloss_key)){
	       			schlossNr = schlossNr ++ prefix ++ schloss_key;
	       			ListAdd(marked_schloesser, schloss_key);
	       		}
       		}
       }
       if (Bool(anz_schubladenSchloss)) {
       		griffinfo = griffinfo ++ anz_schubladenSchloss ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Schubladengriff (mit Schloss)') ++ schlossNr ++ '@n';
       }
       if (Bool(anz_c_schloesser)) {
       		griffinfo = griffinfo ++ anz_c_schloesser ++ 'x ' ++ tuerinfo ++ ' ' ++ Localize('[CO][MB] mit Schubladengriff (mit C-Schloss)') ++ '@n';
       }
    }
    return griffinfo;
   }

def panelingTypes(group_volumes) {
    my paneling = '';
    my positions = 3;
    my sides = 0;
    my mountedpanels = 0;
    my side = '';
    my partly = '';
    my back = '';
    my panels = List();
    my glaspanels = List();
    my rohre = List();
    my rows = List();
    my count = Size(group_volumes);
    my cols = 1; /* Shelfs per row */
    for (my vol : group_volumes) {
      my refparts = GetVolumeRefParts(vol);
      panels = JoinList(panels,FilterList(refparts,'element',`not IsSubTypeOf(element,'metallverkleidung');`));  
      glaspanels = JoinList(glaspanels,FilterList(refparts,'element',`not IsSubTypeOf(element,'glasverkleidung');`));
      rohre = JoinList(rohre,FilterList(refparts,'element',`not IsSubTypeOf(element,'rohr');`));
    }
    panels = FilterList(panels,'element',`not Bool(call vertikalBlech(element));`);
    panels = FilterList(panels,'element',`not Bool(Feature(element,'calculated'));`);
    glaspanels = FilterList(glaspanels,'element',`not call vertikalGlas(element);`);
    glaspanels = FilterList(glaspanels,'element',`not Bool(Feature(element,'calculated'));`);
    mountedpanels = Size(panels) + Size(glaspanels);

    /* Berechnung Seiten, damit vollstaendig verkleidet ausser einer Seite offen oder mit Turren */
    rohre = FilterList(rohre,'element',`Feature(element,'f_horizontal');`);
    for (my rohr : rohre){
      rows = ListAdd(rows, Round(PartPos(rohr)['z']));
    }  
    rows = UniqueList(rows);
    rows = Size(rows);
    if (rows ge 1) {
      cols = count/rows;
    }
    /* Definition der Verkleidung aufgrund der Aussenwaende */
    if (cols eq 1) {
      sides = cols * positions * rows;
    } else if (cols gt 1) {
      sides = ((cols * positions) - ((cols - 2) * 2) - 2) * rows;
    }
    /* Message( mountedpanels ++ ', ' ++ sides ); */
    if (mountedpanels ge sides) {
      paneling = Localize('[CO][MB] inkl. Rück-/und Seitenwände');
    } else if (mountedpanels lt sides) {
      if (mountedpanels gt 0) {
        paneling = Localize('[CO][MB] inkl. Rück-/und Seitenwände (teilweise)');
       }
    }
    return paneling;
     /*
    my group_volumes = call groupIdVolumeList(5);
    call panelingTypes(group_volumes);
    */
    }

def getRALFromColorcodes(colorcodes) {
	call getRALFromColorcodes(colorcodes,'@n',false, true);
};
def getRALFromColorcodes(colorcodes, html) {
	call getRALFromColorcodes(colorcodes,'@n',html, true);
};

def getRALFromColorcodes(colorcodes, sep, html, withral) {
	my inoslist = List('70','71');
	my ral_codes = '';
	my i = 0;
	for (my colorcode: colorcodes) {
		my kbez = colornames['Farbcode',colorcode]['Kurzbezeichnung'];
		my klist = StringToList(kbez, ':');

		my ral_code = '';
		if (Size(klist) gt 1 or InList(inoslist, colorcode)) {
			my  bez = colornames['Farbcode',colorcode]['Bezeichnung_'++UpperCase(Language())];
			my ral = StrLen(klist[1]) and withral ? ' [RAL '++klist[1]++']' : '';
			ral_codes = ral_codes ++ (i gt 0 ? sep : '') ++ bez++ral;
			i = i + 1;
		}; 

	}

	if (html) {
		return PXFormattingToHTML(ral_codes, false);
	} else {
		return ral_codes;
	};

};

def buildVolumeDoorAndShelfInfo(articellist) {
	my doorInfo = call getDoorInfo(articellist);
	my shelfInfo = call getShelfInfo(articellist);
	if (SubStr(shelfInfo,0,2) EQ ', ') {
		shelfInfo = SubStr(shelfInfo,2,StrLen(shelfInfo)-2);
	}
	my fachinfo = doorInfo ++ (StrLen(doorInfo) GT 0 AND StrLen(shelfInfo) GT 0 ? ', ' : '') ++ shelfInfo;
	return fachinfo;
}

def getDoorInfo(articellist){
	my tuerinfo = '';
	for (my part : articellist) {
		my name = GetTypeName(part);
		if (StringContains(name,'tuer') OR StringContains(name,'schublade')){
			if (StringContains(name,'azt')){
				tuerinfo = tuerinfo ++ Localize('[CO][MB] Ausziehtüre');
				for (my element : ChildrenList(part)){
					if (StringContains(GetTypeName(element),'tuer')){
						tuerinfo = tuerinfo ++ ' ' ++  call getHandleInfo(element,'tuer');
					}
				};
			} else if (StringContains(name,'klapp')){
				tuerinfo = tuerinfo ++ Localize('[CO][MB] Klapptüre') ++ ' ' ++ call getHandleInfo(part,'klapp');
			} else if (StringContains(name,'einschub')){
				tuerinfo = tuerinfo ++ Localize('[CO][MB] Einschubtüre') ++ ' ' ++  call getHandleInfo(part,'einschub');
			} else if (StringContains(name,'glas')){
				tuerinfo = tuerinfo ++ Localize('[CO][MB] Glastüre') ++ ' ' ++  call getHandleInfo(part,'glas');
			} else if (StringContains(name,'lade')){
				tuerinfo = tuerinfo ++ Localize('[CO][MB] Schubladen') ++ ' ' ++  call getHandleInfo(part,'lade');
			}
			if (EndsWith(tuerinfo,' ')) {
				tuerinfo = SubStr(tuerinfo,0,StrLen(tuerinfo)-1);
			}
		}
	}
	return tuerinfo;
}

def getHandleInfo(set,kind) {
	my result = '';
	for (my element : ChildrenList(set)){
		if (ChildCount(element) GT 0) {
			for (my child : ChildrenList(element)) {
				result = call getHandleName(child);
			}
		} else {
			result = call getHandleName(element);
		}
	}
	return result;
}

def getHandleName(part) {
		my name = GetTypeName(part);
		if (StringContains(name,'griff') OR StringContains(name,'schloss')){
			if (name EQ 'griff_normal'){
				return Localize('[CO][MB] mit Griff (ohne Schloss)');
			} else if (name EQ 'griff_m_nummer'){
				return Localize('[CO][MB] mit Griff (mit Schloss)');
			} else if (name EQ 'schnapp_griff_normal'){
				return Localize('[CO][MB] mit Schnappdrehgriff (ohne Schloss)');
			} else if (name EQ 'schnapp_griff_m_nummer'){
				return Localize('[CO][MB] mit Schnappdrehgriff (mit Schloss)');
			} else if (name EQ 'chromgriff'){
				return Localize('[CO][MB] mit Chromgriff (ohne Schloss)');
			} else if (name EQ 'glasgriff_schloss_m'){
				return Localize('[CO][MB] mit Glasgriff (mit Schloss)');
			} else if (kind EQ 'lade' AND name EQ 'schublade_schloss_num'){
				return Localize('[CO][MB] mit Schubladengriff (mit Schloss)');
			} else if (kind EQ 'lade' AND name NE 'schublade_schloss_num'){
				return Localize('[CO][MB] mit Schubladengriff (ohne Schloss)');
			}
		} else {
			return '';
		}
}

def getShelfInfo(articellist){
	my tablarinfo = '';
	my nrOfTablar = Dictionary(List('auz','met','glas'),List(0,0,0));
	for (my part : articellist){
		my name = GetTypeName(part);
		if (StringContains(name,'tablar') AND StringContains(name,'zieh')){
			nrOfTablar['auz'] = nrOfTablar['auz'] + 1;
		} else if (StringContains(name,'tablar') AND StringContains(name,'glas')) {
			nrOfTablar['glas'] = nrOfTablar['glas'] + 1;
		} else if (StringContains(name,'tablar') AND !StringContains(name,'zieh') AND !StringContains(name,'glas')) {
			nrOfTablar['met'] = nrOfTablar['met'] + 1;
		}
	}
	return (nrOfTablar['auz'] GT 0 ? ', ' ++ nrOfTablar['auz'] ++ 'x ' ++ Localize('[CO][MB] Auszugstablar') : '')	++ (nrOfTablar['met'] GT 0 ? ', ' ++ nrOfTablar['met'] ++ 'x ' ++ Localize('[CO][MB] Metalltablar') : '') ++ (nrOfTablar['glas'] GT 0 ? ', ' ++  nrOfTablar['glas'] ++ 'x ' ++ Localize('[CO][MB] Glastablar') : '');
}
